head.script:
//전역변수
scwin.memJson = "";
scwin.empNo = "";
scwin.epId = "";
scwin.userId = "";

scwin.curRow = -1; //그리드안에서 돋보기 클릭시 해당되는  row체크

//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // 회원정보를 json 데이터로 모두 받음
    scwin.memJson = $c.data.getMemInfo();

    scwin.empNo = scwin.memJson.empNo;    // 사원번호
    scwin.epId = scwin.memJson.epId;    // 다이렉트 아이디  
    scwin.userId = scwin.memJson.userId;

    var codeOptions = [
        { grpCd: "TL113", compID: "lc_oilUprrglClsCd , gr_oilUnitPrice:oilUprrglClsCd" }, // 거래구분
        { grpCd: "TL110", compID: "lc_oilSellClsCd , gr_oilUnitPrice:oilSellClsCd " }, // 판매단가기준
        { grpCd: "TL103", compID: "gr_oilUnitPrice:oilTskClsCd" },  // 유류업무구분
        { grpCd: "TL100", compID: "gr_oilUnitPrice:oilBizClsCd" },  // 유류사업구분
        { grpCd: "TL101", compID: "gr_oilUnitPrice:selpchClsCd" },  // 매출입구분
        { grpCd: "ZZ021", compID: "gr_oilUnitPrice:apprvStsCd" }   //결재상태
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = async function () {
    dma_search.set('clntNo', ed_clntNo.getValue());
    dma_search.set('oilSellClsCd', lc_oilSellClsCd.getValue());
    dma_search.set('dcsnSts', lc_dcsnSts.getValue());
    dma_search.set('oilUprrglClsCd', lc_oilUprrglClsCd.getValue()); //단가구분 : 02 여신거래, 10 현물거래
    dma_search.set('oilTskClsCd', "F");
    dma_search.set('oilBizClsCd', "01");
    dma_search.set('selpchClsCd', "02");
    dma_search.set('payChkCd', "Y");		// 지급구분 : Y인 경우 여신/현물거래 동시 조회 가능

    await scwin.f_Retrieve();		// 화면 자동조회
    ed_stdDt.focus();
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    ed_stdDt.setValue($c.date.getServerDateTime("yyyyMM") + "01");
    ed_endDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = function () {
    var count = ds_oilUnitPrice.getRowCount();
    if (count < 0) return;

    var payClsNm = "";
    if (ds_oilUnitPrice.getCellData(0, "oilUprrglClsCd") == "01") {
        payClsNm = "[여신거래]";
    } else if (ds_oilUnitPrice.getCellData(0, "oilUprrglClsCd") == "10") {
        payClsNm = "[현물거래]";
    }

    var nameExcel = `유류판매단가${payClsNm}.xlsx`

    var options = {
        fileName: nameExcel,
        sheetName: "유류판매단가",
        startRowIndex: 4,
        startColumnIndex: 0,
        type: 1,
        columnMove: true, //그리드 컬럼이동시 이동된 상태로 다운로드 유무 ( "true"인경우 컬럼이동 순서대로 출력 )
        //evenRowBackgroundColor : "#f5fff5"//excel파일에서 그리드 body의 짝수줄의 배경색
    };

    var infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 14,
        text: "유류판매단가",
        textAlign: "center",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 2,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 14,
        text: `기준일자 [${$c.date.formatDate(ed_stdDt.getValue(), "date")} ~ ${$c.date.formatDate(ed_endDt.getValue(), "date")}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 3,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 14,
        text: `주유소 [${ed_clntNm.getValue()}[${ed_clntNo.getValue()}]]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }];

    $c.data.downloadGridViewExcel(gr_oilUnitPrice, options, infoArr);
};

//-------------------------------------------------------------------------
// 조회기간 체크
//-------------------------------------------------------------------------
scwin.f_CheckAdptDt = async function () {
    if (!await $c.gus.cfValidate([ed_stdDt, ed_endDt]))
        return;

    if (!await $c.gus.cfIsAfterDate(ed_stdDt.getValue(), ed_endDt.getValue(), false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); //시작일자가 종료일자 이전이어야 합니다
        ed_stdDt.focus();
        return;
    }
    return true;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    var vChkVal = await scwin.f_CheckAdptDt();			//날짜 체크한 결과 값을 리턴
    if (!vChkVal) {					//true or false 결과을 체크하여 잘못들어갔다면, false값 리턴
        return false;
    }

    //ds_search.UseChangeInfo = "false";
    dma_search.set('clntNo', ed_clntNo.getValue());
    dma_search.set('oilSellClsCd', lc_oilSellClsCd.getValue());
    dma_search.set('dcsnSts', lc_dcsnSts.getValue());
    dma_search.set('oilUprrglClsCd', lc_oilUprrglClsCd.getValue()); //단가구분 : 02 여신거래, 10 현물거래
    dma_search.set('oilTskClsCd', "F");
    dma_search.set('oilBizClsCd', "01");
    dma_search.set('selpchClsCd', "02");
    dma_search.set('payChkCd', "Y");		// 지급구분 : Y인 경우 여신/현물거래 동시 조회 가능

    $c.sbm.execute(sbm_retrieve);

    setTimeout(function () {
        gr_oilUnitPrice.setColumnReadOnly('oilTskClsCd', true);
        gr_oilUnitPrice.setColumnReadOnly('oilBizClsCd', true);
        gr_oilUnitPrice.setColumnReadOnly('selpchClsCd', true);
        gr_oilUnitPrice.setColumnReadOnly('clntNo', true);
        gr_oilUnitPrice.setColumnReadOnly('clntNm', true);
        gr_oilUnitPrice.setColumnReadOnly('oilUprrglClsCd', true);
        gr_oilUnitPrice.setColumnReadOnly('oilkndCd', true);
        gr_oilUnitPrice.setColumnReadOnly('stdDt', true);
        gr_oilUnitPrice.setColumnReadOnly('endDt', true);
        // gr_oilUnitPrice.setColumnReadOnly('bilgAcctDeptCd', false);
        // gr_oilUnitPrice.setColumnReadOnly('bilgAcctDeptNm', true);
        gr_oilUnitPrice.setColumnReadOnly('sellAcctDeptCd', false);
        gr_oilUnitPrice.setColumnReadOnly('sellAcctDeptNm', true);
        gr_oilUnitPrice.setColumnReadOnly('oilSellClsCd', false);
        gr_oilUnitPrice.setColumnReadOnly('sellClntNo', true);
        gr_oilUnitPrice.setColumnReadOnly('sellClntNm', true);
    }, 100);
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var rowCnt = ds_oilUnitPrice.getRowCount();
        totalRows.setValue(rowCnt);

        if (rowCnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        } else {
            gr_oilUnitPrice.setFocusedCell(0, 'selYn');
        }
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
    if (ds_oilUnitPrice.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ['유류판매단가 그리드']);	//변경된 정보가 없습니다.
        return;
    }
    if (!await $c.gus.cfValidate([gr_oilUnitPrice])) return;

    if (await $c.win.confirm(MSG_CM_CRM_001)) { 				//저장하시겠습니까?		
        for (var i = 0; i < ds_oilUnitPrice.getRowCount(); i++) {
            var RowStatus = ds_oilUnitPrice.getRowStatus(i);		// RowStatus : 기상태:"R", 갱신:"U", 삽입:"C", 삭제:"D", 삽입 후 삭제:"V"

            if (RowStatus == "C" || RowStatus == "U") {
                if (ds_oilUnitPrice.getCellData(i, "oilUprrglClsCd") == "01") { 	// 여신거래
                    ds_oilUnitPrice.setCellData(i, "sellClntNo", "125109");
                    ds_oilUnitPrice.setCellData(i, "sellClntNm", "지에스칼텍스(주)여수공장");
                }
            }
        }

        $c.sbm.execute(sbm_saveOilPrice);
    }
};

scwin.sbm_saveOilPrice_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    var focusCol = gr_oilUnitPrice.getFocusedColumnIndex();
    ds_oilUnitPrice.insertRow();

    //tobe추가 : 그리드 포커스 셋팅
    gr_oilUnitPrice.setFocusedCell(ds_oilUnitPrice.getRowCount() - 1, focusCol);

    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'stdDt', $c.date.getServerDateTime("yyyyMMdd"));
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'endDt', "99999999");
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'oilTskClsCd', "F");
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'oilBizClsCd', "01");
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'selpchClsCd', "02");
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'oilUprrglClsCd', lc_oilUprrglClsCd.getValue());
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'sellClntNo', "125109");
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'sellClntNm', "지에스칼텍스(주)여수공장");
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'oilkndCd', ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition() - 1, 'oilkndCd'));
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'bilgAcctDeptCd', ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition() - 1, 'bilgAcctDeptCd'));
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'bilgAcctDeptNm', ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition() - 1, 'bilgAcctDeptNm'));
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'sellAcctDeptCd', ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition() - 1, 'sellAcctDeptCd'));
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'sellAcctDeptNm', ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition() - 1, 'sellAcctDeptNm'));
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'qty', 1);
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'toQty', 9999999999);
    ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), 'oilSellClsCd', "01");						// 유류판매구분코드 : 01 공장도가, 07 판매기준단가

    gr_oilUnitPrice.setColumnReadOnly('oilTskClsCd', false);
    gr_oilUnitPrice.setColumnReadOnly('oilBizClsCd', false);
    gr_oilUnitPrice.setColumnReadOnly('selpchClsCd', false);
    gr_oilUnitPrice.setColumnReadOnly('clntNo', false);
    gr_oilUnitPrice.setColumnReadOnly('clntNm', true);
    gr_oilUnitPrice.setColumnReadOnly('oilUprrglClsCd', false);
    gr_oilUnitPrice.setColumnReadOnly('oilkndCd', false);
    gr_oilUnitPrice.setColumnReadOnly('stdDt', false);
    gr_oilUnitPrice.setColumnReadOnly('endDt', true);
    // gr_oilUnitPrice.setColumnReadOnly('bilgAcctDeptCd', false);
    // gr_oilUnitPrice.setColumnReadOnly('bilgAcctDeptNm', true);
    gr_oilUnitPrice.setColumnReadOnly('sellAcctDeptCd', false);
    gr_oilUnitPrice.setColumnReadOnly('sellAcctDeptNm', true);
    gr_oilUnitPrice.setColumnReadOnly('sellClntNo', false);
    gr_oilUnitPrice.setColumnReadOnly('sellClntNm', true);
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = async function () {
    var focusRow = gr_oilUnitPrice.getFocusedRowIndex(); //현재 포커스 되어있는 row
    var focusCol = gr_oilUnitPrice.getFocusedColumnIndex(); //현재 포커스 되어있는 column

    if (ds_oilUnitPrice.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
        return;
    }

    var chkCnt = 0;
    var chkRowIdx = gr_oilUnitPrice.getCheckedIndex("selYn"); //체크된 행의인덱스

    for (var i = 0; i < chkRowIdx.length; i++) {
        var tempStdCd = ds_oilUnitPrice.getCellData(chkRowIdx[i], "apprvStsCd");
        if (tempStdCd == "02" || tempStdCd == "04" || tempStdCd == "05") { 	// 02:상신, 04:중간승인, 05:최종승인
            await $c.gus.cfAlertMsg((chkRowIdx[i] + 1) + "번째 항목은 삭제 할 수 없습니다.\n결재상태를 확인해 주시기바랍니다.");
            ds_oilUnitPrice.setRowPosition(chkRowIdx[i]);
            gr_oilUnitPrice.setFocusedCell(chkRowIdx[i], "apprvStsCd");
            return;
        }
        chkCnt++;
    }

    if (chkCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }

    //tobe 변경 : 추가된 행 삭제시 화면에서도 바로 삭제. 추가된 행이 아닌경우, 화면에서는 지워지지 않고 status만 삭제표시
    //ds_oilUnitPrice.DeleteRow(ds_oilUnitPrice.RowPosition);
    if (ds_oilUnitPrice.getRowStatus(focusRow) == "C") { //추가된 행
        ds_oilUnitPrice.removeRow(focusRow)

    } else {
        ds_oilUnitPrice.deleteRow(focusRow);

        for (var i = 0; i < 24; i++) {
            ds_oilUnitPrice.setCellData(focusRow, ds_oilUnitPrice.getColumnID(i), ds_oilUnitPrice.getOriginalCellData(focusRow, ds_oilUnitPrice.getColumnID(i)));
        }

        //deleteRow 이후, 포커스 유지
        gr_oilUnitPrice.setFocusedCell(focusRow, focusCol);

    }
};

//-------------------------------------------------------------------------
// 	팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:					// 거래처
            await udc_clnt.cfCommonPopUp(scwin.udc_clnt_callbackFunc, pCode, pName, 'T', null, null, null, null, null, null, null, null, null);
            break;
        default:
            break;
    }
};

//거래처 팝업 콜백
scwin.udc_clnt_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;	 // 짝이 되는 오브젝트의 값 제거

    await $c.gus.cfClearPairObj(pairObj);											// 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);										// inObj가 코드 필드일 경우 팝업
    if ($c.gus.cfIsNull(isCode) || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 체크박스 선택 상태 유무 체크 => tobe삭제 : gr_oilUnitPrice.getCheckedIndex('selYn').length로 대체
//-------------------------------------------------------------------------
// scwin.f_checkflag = function() {
//     for( var idx=1; idx <= ds_oilUnitPrice.CountRow ; idx++) {
//         if (ds_oilUnitPrice.NameValue(idx, "selYn") == "T"){
//             return true;
//         }
//     }
//     return false;
// };

//-------------------------------------------------------------------------
// 전자결제 
//-------------------------------------------------------------------------
scwin.f_RequestElectronicApprove = async function (e) {
    var toDay = $c.date.getServerDateTime("yyyyMMdd");

    var vReqApprvDocKndCd = "021"					// 결재문서종류 -- 유류판매단가 내역
    var vReqUserId = scwin.userId;  	// 결재요청자 ID
    var vEpUsrId = scwin.epId; //f_getSSOInfo();   				// EP사용자 ID

    var fineInfo = scwin.f_getFineItemList();             // 결재대상 (유류단가 정보)

    if (fineInfo.itemSize == 0) {
        await $c.gus.cfAlertMsg("전자결재 대상을 선택해주십시오.");
        return false;
    }

    var payClsNm = "";
    var chkRowIdx = gr_oilUnitPrice.getCheckedIndex("selYn");

    for (var i = 0; i < chkRowIdx.length; i++) {
        var tempStdCd = ds_oilUnitPrice.getCellData(chkRowIdx[i], "apprvStsCd");
        if (tempStdCd == "02" || tempStdCd == "04" || tempStdCd == "05") { 	// 02:상신, 04:중간승인, 05:최종승인
            await $c.gus.cfAlertMsg((chkRowIdx[i] + 1) + "번째 항목은 전자결재를 진행 할 수 없습니다.\n결재상태를 확인해 주시기바랍니다.");
            ds_oilUnitPrice.setRowPosition(chkRowIdx[i]);
            gr_oilUnitPrice.setFocusedCell(chkRowIdx[i], "apprvStsCd");
            return;
        }
        if (payClsNm == "") {
            if (ds_oilUnitPrice.getCellData(chkRowIdx[i], "oilUprrglClsCd") == "01") {
                payClsNm = "[여신거래]";
            } else if (ds_oilUnitPrice.getCellData(chkRowIdx[i], "oilUprrglClsCd") == "10") {
                payClsNm = "[현물거래]";
            }
        }
    }

    if (await $c.win.confirm("전자결재 요청하시겠습니까?") != true) {
        return;
    }

    var vReqApprvTitle = "FMS 유류 판매단가" + payClsNm + " 승인요청_" + toDay;	//결재제목 

    var styleTb = 'class=tb';
    var vApprvDtlInfo = '<head>';
    vApprvDtlInfo += '<style type=text/css>';
    vApprvDtlInfo += '	.tb { ';
    vApprvDtlInfo += '		border-top:solid 1px #000000;';
    vApprvDtlInfo += '		border-right:solid 1px #000000;';
    vApprvDtlInfo += '		border-left:solid 1px #000000; ';
    vApprvDtlInfo += '		border-bottom:solid 1px #000000;';
    vApprvDtlInfo += '	}';
    vApprvDtlInfo += '</style>';
    vApprvDtlInfo += '</head>';
    vApprvDtlInfo += '<body align=center>';
    vApprvDtlInfo += '<table width=850 cellspacing=0 cellpadding=0 border=1 ' + styleTb + '>';
    vApprvDtlInfo += '	<tr>';
    vApprvDtlInfo += '		<td height=35 align=center ' + styleTb + '>제 목</td>';
    vApprvDtlInfo += '		<td ' + styleTb + '><b>FMS 유류 판매단가' + payClsNm + ' 승인요청 -  (' + toDay + ')</b></td>';
    vApprvDtlInfo += '	</tr>';
    vApprvDtlInfo += '	<tr>';
    vApprvDtlInfo += '		<td colspan=2 ' + styleTb + '>';
    vApprvDtlInfo += '			<table width=850 border=0>';
    vApprvDtlInfo += '				<tr>';
    vApprvDtlInfo += '					<td colspan=2 height=10 align=center>&nbsp;</td>';
    vApprvDtlInfo += '				</tr>';
    vApprvDtlInfo += '				<tr>';
    vApprvDtlInfo += '					<td colspan=2>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;아래와 같이 FMS 유류판매단가' + payClsNm + ' 를 확정하고자 하오니 승인하여 주시기 바랍니다.</td>';
    vApprvDtlInfo += '				</tr>';
    vApprvDtlInfo += '				<tr>';
    vApprvDtlInfo += '					<td colspan=2 height=10 align=center>&nbsp;</td>';
    vApprvDtlInfo += '				</tr>';
    vApprvDtlInfo += '				<tr>';
    vApprvDtlInfo += '					<td colspan=2 align=center><font face=굴림><b>- 아&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;래 -</b></font></td>';
