    var oilCount = 0;

    for (var i = 0; i < chkRowIdx.length; i++) {
        var stdDt1 = ds_oilUnitPrice.getCellData(chkRowIdx[i], "stdDt");
        var payClsCd1 = '';

        if (ds_oilUnitPrice.getCellData(chkRowIdx[i], "oilUprrglClsCd") == "01") {
            payClsCd1 = "여신거래";
