        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + ds_oilUnitPrice.getCellData(chkRowIdx[i], "clntNo") + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + ds_oilUnitPrice.getCellData(chkRowIdx[i], "clntNm") + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + payClsCd1 + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + ds_oilUnitPrice.getCellData(chkRowIdx[i], "sellClntNo") + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + ds_oilUnitPrice.getCellData(chkRowIdx[i], "sellClntNm") + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + $c.gus.cfInsertComma($c.num.parseFloat(ds_oilUnitPrice.getCellData(chkRowIdx[i], "uprLight"))) + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + $c.gus.cfInsertComma($c.num.parseFloat(ds_oilUnitPrice.getCellData(chkRowIdx[i], "uprGasoline"))) + '</font></td>';
        vApprvDtlInfo += '								<td ' + styleTb + ' align=center><font size=2 face=굴림>' + ds_oilUnitPrice.getCellData(chkRowIdx[i], "sellAcctDeptNm") + '</font></td>';
        vApprvDtlInfo += '							</tr>';
        oilCount++;
    }
    vApprvDtlInfo += '						</table>';
    vApprvDtlInfo += '					</td>';
    vApprvDtlInfo += '				</tr>';
    vApprvDtlInfo += '				<tr>';
    vApprvDtlInfo += '					<td align=right colspan=2><font face=굴림><b>이상 ' + oilCount + '건</b></font></td>';
    vApprvDtlInfo += '				</tr>';

    vApprvDtlInfo += '			</table>';
    vApprvDtlInfo += '		</td>';
    vApprvDtlInfo += '	</tr>';
    vApprvDtlInfo += '</table>';
    vApprvDtlInfo += '</body>';


    // ======================================================================

    const params = {
        apprvDocKndCd: vReqApprvDocKndCd,  //결재문서종류  
        reqUserId: vReqUserId,  //결재요청자
        epUserId: vEpUsrId,  //EP사용자
        apprvTitle: vReqApprvTitle,  //결재제목
        apprvDtlInfo: vApprvDtlInfo,  //결제문서양식
        OilunitPriceList: fineInfo.itemList,  //결제대상
        bmodifylines: "Y",  //문서정보 변경 가능 여부
        bmodifybody: "Y",  //문서 본문 수정 여부
        bmodifyattach: "Y"  //첨부파일 기능 활성화 여부
    };

    // DataMap에 세팅
    dma_approve.setJSON(params);

    // 여기부터가 핵심: f_aprv처럼 팝업 + POST submit
    let url = "/ps.eq.fmsmgnt.RequestFmsOilUnitPriceApproveCMD.do";
    let targetName = "aprvPopup"; // 고정 이름 재사용

    var data = dma_approve.getJSON() || {};

    const form = document.createElement("form");
    form.method = "POST";
    form.action = url;
    form.target = targetName;

    // 팝업 차단 회피: 사용자 confirm 이후 즉시 open
    const win = window.open("", targetName);
    if (!win) {
        console.warn("Popup blocked");
        // 필요하면 여기서 alert 처리
        // $c.win.alert("팝업이 차단되었습니다. 팝업 허용 후 다시 시도해 주세요.");
    }

    Object.keys(data).forEach((key) => {
        const input = document.createElement("input");
        input.type = "hidden";
        input.name = key;

        // 배열/객체는 서버가 JSON 문자열로 받는 구조인지 확인 필요.
        // 보통은 stringify 해서 보내는 게 안전함.
        const val = data[key];
        input.value =
            (val && typeof val === "object")
                ? JSON.stringify(val)
                : (val ?? "").toString();

        form.appendChild(input);
    });

    document.body.appendChild(form);
    form.submit();
    document.body.removeChild(form);
};

